// Extract message data from Telegram
const msg = $input.item.json.message || $input.item.json;

// CRITICAL: Use from.id for consistent user identification
const userId = msg.from?.id || msg.chat?.id;
const chatId = msg.chat?.id;
const userName = msg.from?.first_name || msg.from?.username || 'Customer';
const messageText = (msg.text || '').trim();

// Convert to string for consistency
const consistentUserId = String(userId);

console.log('=== USER IDENTIFICATION ===');
console.log('User ID (from.id):', userId);
console.log('Chat ID:', chatId);
console.log('Message:', messageText);

return {
  json: {
    message: msg,  // Keep original for other uses
    chatId: String(chatId),
    userId: consistentUserId,  // ‚Üê THIS is what memory uses
    userName: userName,
    userMessage: messageText,
    timestamp: new Date().toISOString()
  }
};

// Parse booking details from AI's confirmation message
const aiResponse = $('AI Agent').item.json.output || '';
const userName = $('Extract User Data').item.json.userName || 'Customer';
const userId = $('Extract User Data').item.json.userId || '';
const chatId = $('Extract User Data').item.json.chatId || '';

console.log('=== PARSING BOOKING ===');
console.log('AI Response:', aiResponse);

// Helper function to extract info
function extractField(text, markers) {
  for (const marker of markers) {
    const regex = new RegExp(marker + '\\s*:?\\s*([^\\n-]+)', 'i');
    const match = text.match(regex);
    if (match) {
      return match[1].trim().replace(/\(.*?\)/g, '').trim();
    }
  }
  return null;
}

// Extract booking details
let service = extractField(aiResponse, ['Service', '- Service']);
let date = extractField(aiResponse, ['Date', '- Date']);
let time = extractField(aiResponse, ['Time', '- Time']);
let phone = extractField(aiResponse, ['Phone', '- Phone']);

// Extract price
let price = 'N/A';
const priceMatch = aiResponse.match(/‚Çπ(\d+)/);
if (priceMatch) {
  price = priceMatch[1];
}

// Extract duration
let duration = '30';
const durationMatch = aiResponse.match(/(\d+)min/);
if (durationMatch) {
  duration = durationMatch[1];
}

// Generate unique booking ID
const bookingId = `BK${Date.now()}`;

// Format date
let formattedDate = date || 'Not specified';
let bookingDateObj = new Date();

// Parse "March 2, 2026" or "2nd march" format
if (date) {
  const dateMatch = date.match(/(\w+)\s+(\d+)/i);
  if (dateMatch) {
    const month = dateMatch[1];
    const day = parseInt(dateMatch[2]);
    const year = new Date().getFullYear();

    const monthMap = {
      'january': 0, 'jan': 0,
      'february': 1, 'feb': 1,
      'march': 2, 'mar': 2,
      'april': 3, 'apr': 3,
      'may': 4,
      'june': 5, 'jun': 5,
      'july': 6, 'jul': 6,
      'august': 7, 'aug': 7,
      'september': 8, 'sep': 8,
      'october': 9, 'oct': 9,
      'november': 10, 'nov': 10,
      'december': 11, 'dec': 11
    };

    const monthNum = monthMap[month.toLowerCase()];
    if (monthNum !== undefined) {
      bookingDateObj = new Date(year, monthNum, day);
      formattedDate = bookingDateObj.toLocaleDateString('en-IN', {
        weekday: 'long',
        day: 'numeric',
        month: 'long',
        year: 'numeric'
      });
    }
  }
}

// Parse time to 24-hour format
let hour = 17; // Default 5 PM
let minute = 0;
if (time) {
  const timeMatch = time.match(/(\d+):?(\d{0,2})\s*(AM|PM)?/i);
  if (timeMatch) {
    hour = parseInt(timeMatch[1]);
    minute = parseInt(timeMatch[2] || 0);
    const ampm = (timeMatch[3] || 'PM').toUpperCase();

    if (ampm === 'PM' && hour !== 12) hour += 12;
    if (ampm === 'AM' && hour === 12) hour = 0;
  }
}

// Set time on booking date
bookingDateObj.setHours(hour, minute, 0, 0);

console.log('Extracted Values:');
console.log('- Service:', service);
console.log('- Date:', formattedDate);
console.log('- Time:', time);
console.log('- Phone:', phone);
console.log('- Price:', price);

return {
  json: {
    bookingId,
    customerName: userName,
    userId,
    chatId,
    service: service || 'Not specified',
    servicePrice: price,
    serviceDuration: duration,
    date: formattedDate,
    bookingDate: bookingDateObj.toISOString(),
    bookingDateObj: bookingDateObj.toISOString().split('T')[0], // YYYY-MM-DD
    time: time || 'Not specified',
    bookingHour: hour,
    bookingMinute: minute,
    phone: phone || 'Not specified',
    status: 'Confirmed',
    createdAt: new Date().toISOString(),
    staffAssigned: 'Pending',
    calendarEventId: '',
    notificationSent: 'No'
  }
};

// Get booking and staff list
const booking = $('Parse Booking Details').item.json;
const allStaff = $input.all(); // All staff from sheet

const service = (booking.service || '').toLowerCase();

console.log('=== STAFF ASSIGNMENT ===');
console.log('Service:', service);
console.log('Available Staff:', allStaff.length);

// Filter active staff who can do this service
const capableStaff = allStaff.filter(item => {
  const staff = item.json;
  const isActive = (staff.Status || '').toLowerCase() === 'active';
  const services = (staff.Services || '').toLowerCase();

  console.log(`Checking ${staff['Staff Name']}: Active=${isActive}, Services=${services}`);

  // Check if staff can do this service
  const canDoService = services.split(',').some(s => 
    service.includes(s.trim()) || s.trim().includes(service.split(' ')[0])
  );

  return isActive && canDoService;
});

console.log('Capable Staff:', capableStaff.length);

// If no one can do it specifically, use any active staff
let selectedStaff = capableStaff.length > 0 ? capableStaff : 
                     allStaff.filter(item => 
                       (item.json.Status || '').toLowerCase() === 'active'
                     );

// Round-robin or random selection
const staffIndex = Math.floor(Math.random() * selectedStaff.length);
const assignedStaff = selectedStaff[staffIndex]?.json || {
  'Staff ID': 'UNASSIGNED',
  'Staff Name': 'To Be Assigned',
  'Calendar ID': ''
};

console.log('Assigned to:', assignedStaff['Staff Name']);

return {
  json: {
    ...booking,
    staffId: assignedStaff['Staff ID'],
    staffName: assignedStaff['Staff Name'],
    calendarId: assignedStaff['Calendar ID'],
    staffAssigned: assignedStaff['Staff Name']
  }
};

const booking = $input.item.json;

// Parse time from "5:00 PM"
function parseTime(timeStr) {
  const match = (timeStr || '').match(/(\d+):?(\d{0,2})?\s*(AM|PM)/i);
  if (!match) return { hour: 17, minute: 0 };

  let hour = parseInt(match[1]);
  const minute = parseInt(match[2] || 0);
  const ampm = match[3].toUpperCase();

  if (ampm === 'PM' && hour !== 12) hour += 12;
  if (ampm === 'AM' && hour === 12) hour = 0;

  return { hour, minute };
}

const { hour, minute } = parseTime(booking.time);

// Build LOCAL date manually (Asia/Kolkata safe)
const [year, month, day] = booking.bookingDateObj.split('-');

// month - 1 because JS months are 0 indexed
const startDate = new Date(
  Number(year),
  Number(month) - 1,
  Number(day),
  hour,
  minute,
  0
);

// 30 minute duration
const endDate = new Date(startDate.getTime() + (booking.serviceDuration || 30) * 60000);

return {
  json: {
    ...booking,
    calendarStartDateTime: startDate.toISOString(),
    calendarEndDateTime: endDate.toISOString()
  }
};

const booking = $('Format DateTime').item.json;
const calendarEvent = $input.item.json;

return {
  json: {
    ...booking,
    calendarEventId: calendarEvent.id || '',
    calendarEventLink: calendarEvent.htmlLink || ''
  }
};

const now = new Date();

// Current time info
const currentTime = now.toLocaleString('en-IN', {
  hour: '2-digit',
  minute: '2-digit',
  hour12: true,
  timeZone: 'Asia/Kolkata'
});

const currentDate = now.toLocaleDateString('en-IN', {
  weekday: 'long',
  day: 'numeric',
  month: 'long',
  year: 'numeric',
  timeZone: 'Asia/Kolkata'
});

const currentHour = now.getHours();
const currentMinute = now.getMinutes();

return {
  json: {
    ...($input.item.json),
    currentTime: currentTime,
    currentDate: currentDate,
    currentHour: currentHour,
    currentMinute: currentMinute,
    currentTimestamp: now.toISOString()
  }
};

const booking = $input.item.json;

return {
  json: {
    chatId: booking.chatId || booking["User ID"],

    message: `‚úÖ BOOKING CONFIRMED! üéâ

üìã Booking ID: ${booking["Booking ID"]}

üë§ Name: ${booking["Customer Name"]}
üì± Phone: ${booking["Phone"]}

üíá Service: ${booking["Service"]}
üí∞ Price: ‚Çπ${booking["Price"]}

üìÖ Date: ${booking["Date"]}
‚è∞ Time: ${booking["Time"]}
üë© Staff: ${booking["Staff Assigned"]}

üìç Location: house of salon
kap india pune, maharashtra

‚öÝÔ∏è Please arrive 5 minutes early.
Bring your Booking ID: ${booking["Booking ID"]}

Thank you for choosing us! üíñ`
  }
};
